        return batch.pin_memory()
    if isinstance(x, string_classes): return bach
    raise TypeError("Batch must contain be in structure of dicts, lists or tuples; found {}"
                     .format(type(batch)))

def get_tensor(batch, pin): return sapply(batch, pin_memory) if pin else batch
```

